      const y = Math.floor(this.y);
      ctx.fillStyle = this.color;
      ctx.fillRect(x, y, this.w, this.h);
      ctx.fillStyle = '#000';
      ctx.fillRect(x+6, y+8, 6, 6);
      ctx.fillRect(x+this.w-12, y+8, 6, 6);
