          this.lives -= 1;
          const sp = this.level.getSpawn();
          this.player.x = sp.x; this.player.y = sp.y;
          this.player.vx = 0; this.player.vy = 0;
          this.cameraX = clamp(this.player.x - this.canvas.width*0.35, 0, this.level.getWorldWidth() - this.canvas.width);
          if (this.lives <= 0){
